fn probe_checkpoint_row_fetch_direct_immutable_select_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchDirectImmutableSelectProbeTestBehavior>,
) -> CheckpointRowFetchDirectImmutableSelectProbeDiagnostic {
    let mut diagnostic = CheckpointRowFetchDirectImmutableSelectProbeDiagnostic::unproven(
        config_path,
        "checkpoint row-fetch direct immutable select probe did not run".to_string(),
    );
    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_DIRECT_IMMUTABLE_SELECT_PROBE_BUDGET_SOURCE.to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_observed = true;

    let (tx, rx) = mpsc::sync_channel(32);
    let config_path_for_worker = config_path.to_path_buf();
    let runtime_db_path_for_worker = runtime_db_path.clone();
    thread::spawn(move || {
        let _ = probe_checkpoint_row_fetch_direct_immutable_select_worker(
            &config_path_for_worker,
            &runtime_db_path_for_worker,
            tx,
            #[cfg(test)]
            test_behavior,
        );
    });

    let mut current_stage = CheckpointRowFetchDirectImmutableSelectProbeStage::OpenRuntimeDb;
    loop {
        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::RuntimeDbInfo {
                uri,
                mode,
                immutable,
                readonly,
            }) => {
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_runtime_db_uri =
                    Some(uri);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_runtime_db_mode =
                    mode;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_runtime_db_immutable =
                    immutable;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_runtime_db_readonly =
                    readonly;
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::Entered(stage)) => {
                current_stage = stage;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(stage.as_str().to_string());
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::BusyTimeout(value)) => {
                current_stage = CheckpointRowFetchDirectImmutableSelectProbeStage::LoadBusyTimeout;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_busy_timeout_ms =
                    Some(value);
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::ConnectionReadMode {
                journal_mode,
                locking_mode,
                query_only,
            }) => {
                current_stage =
                    CheckpointRowFetchDirectImmutableSelectProbeStage::LoadConnectionMetadata;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_connection_journal_mode =
                    Some(journal_mode);
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_connection_locking_mode =
                    Some(locking_mode);
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_connection_query_only =
                    Some(query_only);
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::QueryPlan {
                explain_query_plan,
                explain_query_plan_rows,
            }) => {
                current_stage =
                    CheckpointRowFetchDirectImmutableSelectProbeStage::LoadExplainQueryPlan;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_explain_query_plan =
                    Some(explain_query_plan);
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_explain_query_plan_rows =
                    Some(explain_query_plan_rows);
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::SelectQueryStarted) => {
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_query_started = true;
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::SelectFailed {
                result_kind,
                sqlite_error_code,
                sqlite_error_message,
            }) => {
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_result_kind =
                    Some(result_kind);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_code =
                    sqlite_error_code;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_message =
                    sqlite_error_message;
            }
            Ok(
                CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::SelectRowFetchCompleted {
                    elapsed_ms,
                    row_returned,
                    phase,
                    updated_at,
                    result_kind,
                    sqlite_error_code,
                    sqlite_error_message,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchDirectImmutableSelectProbeStage::RowFetchDirectSelect;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_row_fetch_completed =
                    true;
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_row_fetch_elapsed_ms =
                    elapsed_ms;
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_select_probe_select_row_returned =
                    Some(row_returned);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_select_phase = phase;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_select_updated_at =
                    updated_at;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_result_kind =
                    Some(result_kind);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_code =
                    sqlite_error_code;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_message =
                    sqlite_error_message;
            }
            Ok(CheckpointRowFetchDirectImmutableSelectProbeWorkerMessage::Finished(result)) => {
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                match result {
                    Ok(()) => {
                        diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_reason_class =
                            match diagnostic
                                .checkpoint_row_fetch_direct_immutable_select_probe_result_kind
                            {
                                Some(
                                    CheckpointRowFetchDirectImmutableSelectProbeResultKind::Row
                                    | CheckpointRowFetchDirectImmutableSelectProbeResultKind::Eof
                                    | CheckpointRowFetchDirectImmutableSelectProbeResultKind::SqliteBusy
                                    | CheckpointRowFetchDirectImmutableSelectProbeResultKind::SqliteLocked
                                    | CheckpointRowFetchDirectImmutableSelectProbeResultKind::OtherSqliteError
                                    | CheckpointRowFetchDirectImmutableSelectProbeResultKind::OtherError,
                                ) => CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeProvenChangedByConnectionShape,
                                None => CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeUnprovenDueToMissingEvidence,
                            };
                        diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation =
                            match diagnostic
                                .checkpoint_row_fetch_direct_immutable_select_probe_reason_class
                            {
                                CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeProvenChangedByConnectionShape => {
                                    match diagnostic
                                        .checkpoint_row_fetch_direct_immutable_select_probe_result_kind
                                    {
                                        Some(CheckpointRowFetchDirectImmutableSelectProbeResultKind::Row) => {
                                            "direct immutable runtime-db SELECT changed the connection-shape outcome: rows.next() returned a row".to_string()
                                        }
                                        Some(CheckpointRowFetchDirectImmutableSelectProbeResultKind::Eof) => {
                                            "direct immutable runtime-db SELECT changed the connection-shape outcome: rows.next() returned eof".to_string()
                                        }
                                        Some(result_kind) => format!(
                                            "direct immutable runtime-db SELECT changed the connection-shape outcome: result_kind={} sqlite_error_code={} sqlite_error_message={}",
                                            serde_json::to_string(&result_kind)
                                                .unwrap_or_else(|_| "\"unknown\"".to_string())
                                                .trim_matches('\"'),
                                            diagnostic
                                                .checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_code
                                                .as_deref()
                                                .unwrap_or("null"),
                                            diagnostic
                                                .checkpoint_row_fetch_direct_immutable_select_probe_sqlite_error_message
                                                .as_deref()
                                                .unwrap_or("null"),
                                        ),
                                        None => "direct immutable runtime-db SELECT probe ended without a conclusive connection-shape result".to_string(),
                                    }
                                }
                                CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeProvenNotChangedByConnectionShape => unreachable!(),
                                CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeBudgetExhausted => unreachable!(),
                                CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeUnprovenDueToMissingEvidence => {
                                    "direct immutable runtime-db SELECT probe ended without a conclusive connection-shape result".to_string()
                                }
                            };
                    }
                    Err(error) => {
                        diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_reason_class =
                            CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeUnprovenDueToMissingEvidence;
                        diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation =
                            error;
                    }
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_budget_exhausted =
                    true;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_stage =
                    Some(current_stage.as_str().to_string());
                if current_stage
                    == CheckpointRowFetchDirectImmutableSelectProbeStage::RowFetchDirectSelect
                    && diagnostic
                        .checkpoint_row_fetch_direct_immutable_select_probe_select_query_started
                    && !diagnostic
                        .checkpoint_row_fetch_direct_immutable_select_probe_select_row_fetch_completed
                {
                    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_reason_class =
                        CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeProvenNotChangedByConnectionShape;
                    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation = format!(
                        "direct immutable runtime-db SELECT did not change the exact connection-shape seam: the probe still exhausted its bounded budget after query start and before row-fetch completion at stage={}",
                        current_stage.as_str()
                    );
                } else {
                    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_reason_class =
                        CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeBudgetExhausted;
                    diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation = format!(
                        "checkpoint row-fetch direct immutable SELECT probe exhausted its bounded budget while executing stage={}",
                        current_stage.as_str()
                    );
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_reason_class =
                    CheckpointRowFetchDirectImmutableSelectProbeReasonClass::CheckpointRowFetchDirectImmutableSelectProbeUnprovenDueToMissingEvidence;
                diagnostic.checkpoint_row_fetch_direct_immutable_select_probe_explanation =
                    "checkpoint row-fetch direct immutable SELECT probe worker disconnected before returning a result"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

