fn probe_checkpoint_row_fetch_direct_immutable_single_column_selects_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableSingleColumnProbeTestBehavior,
    >,
) -> CheckpointRowFetchDirectImmutableSingleColumnProbeDiagnostic {
    let mut diagnostic = CheckpointRowFetchDirectImmutableSingleColumnProbeDiagnostic::unproven(
        config_path,
        "checkpoint row-fetch direct immutable single-column probe did not run".to_string(),
    );
    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_DIRECT_IMMUTABLE_SINGLE_COLUMN_PROBE_BUDGET_SOURCE.to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    let runtime_db_uri = build_sqlite_immutable_read_only_uri(&runtime_db_path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_runtime_db_uri =
        Some(runtime_db_uri);
    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_observed = true;

    #[cfg(test)]
    let test_sync = test_behavior.map(|_| {
        Arc::new(CheckpointRowFetchDirectImmutableSingleColumnProbeTestSync::default())
    });

    let (tx, rx) = mpsc::sync_channel(64);
    for target in [
        CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase,
        CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt,
    ] {
        let runtime_db_path_for_worker = runtime_db_path.clone();
        let tx = tx.clone();
        #[cfg(test)]
        let test_sync_for_worker = test_sync.clone();
        thread::spawn(move || {
            let _ = probe_checkpoint_row_fetch_direct_immutable_single_column_worker(
                target,
                &runtime_db_path_for_worker,
                tx,
                #[cfg(test)]
                test_behavior,
                #[cfg(test)]
                test_sync_for_worker,
            );
        });
    }
    drop(tx);

    let mut phase_state = CheckpointRowFetchDirectImmutableSingleColumnSubprobeState::default();
    let mut updated_at_state =
        CheckpointRowFetchDirectImmutableSingleColumnSubprobeState::default();

    loop {
        if phase_state.is_conclusive() && updated_at_state.is_conclusive() {
            apply_direct_immutable_single_column_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase,
                &phase_state,
                &mut diagnostic,
            );
            apply_direct_immutable_single_column_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt,
                &updated_at_state,
                &mut diagnostic,
            );
            diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_total_elapsed_ms =
                elapsed_ms(total_started_at);
            diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_reason_class =
                CheckpointRowFetchDirectImmutableSingleColumnProbeReasonClass::CheckpointRowFetchDirectImmutableSingleColumnProbeProven;
            diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                format!(
                    "direct immutable single-column projection split probe completed with bounded outcomes: {} {}",
                    summarize_direct_immutable_single_column_subprobe(
                        "phase_select",
                        phase_state.result_kind
                    ),
                    summarize_direct_immutable_single_column_subprobe(
                        "updated_at_select",
                        updated_at_state.result_kind
                    )
                );
            return diagnostic;
        }

        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(message) => {
                let state = match &message {
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::Entered {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::BusyTimeout {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::ConnectionReadMode {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::QueryPlan {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectQueryStarted {
                        target,
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectFailed {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::Finished {
                        target,
                        ..
                    } => match target {
                        CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase => {
                            &mut phase_state
                        }
                        CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt => {
                            &mut updated_at_state
                        }
                    },
                };

                match message {
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::Entered {
                        stage,
                        ..
                    } => {
                        state.current_stage = stage;
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::BusyTimeout {
                        value,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableSingleColumnSubprobeStage::LoadBusyTimeout;
                        state.busy_timeout_ms = Some(value);
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::ConnectionReadMode {
                        journal_mode,
                        locking_mode,
                        query_only,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableSingleColumnSubprobeStage::LoadConnectionMetadata;
                        state.connection_journal_mode = Some(journal_mode);
                        state.connection_locking_mode = Some(locking_mode);
                        state.connection_query_only = Some(query_only);
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::QueryPlan {
                        explain_query_plan,
                        explain_query_plan_rows,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableSingleColumnSubprobeStage::LoadExplainQueryPlan;
                        state.explain_query_plan = Some(explain_query_plan);
                        state.explain_query_plan_rows = Some(explain_query_plan_rows);
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectQueryStarted {
                        ..
                    } => {
                        state.query_started = true;
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectFailed {
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::SelectRowFetchCompleted {
                        elapsed_ms,
                        row_returned,
                        value,
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableSingleColumnSubprobeStage::RowFetchSelect;
                        state.row_fetch_completed = true;
                        state.row_fetch_elapsed_ms = elapsed_ms;
                        state.row_returned = Some(row_returned);
                        state.value = value;
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableSingleColumnProbeWorkerMessage::Finished {
                        result,
                        ..
                    } => match result {
                        Ok(()) => {
                            state.finished = true;
                        }
                        Err(error) => {
                            apply_direct_immutable_single_column_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase,
                                &phase_state,
                                &mut diagnostic,
                            );
                            apply_direct_immutable_single_column_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt,
                                &updated_at_state,
                                &mut diagnostic,
                            );
                            diagnostic
                                .checkpoint_row_fetch_direct_immutable_single_column_probe_total_elapsed_ms =
                                elapsed_ms(total_started_at);
                            diagnostic
                                .checkpoint_row_fetch_direct_immutable_single_column_probe_reason_class =
                                CheckpointRowFetchDirectImmutableSingleColumnProbeReasonClass::CheckpointRowFetchDirectImmutableSingleColumnProbeUnprovenDueToMissingEvidence;
                            diagnostic
                                .checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                                error;
                            return diagnostic;
                        }
                    },
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                if phase_state.query_started
                    && !phase_state.row_fetch_completed
                    && phase_state.result_kind.is_none()
                {
                    phase_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableSingleColumnProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }
                if updated_at_state.query_started
                    && !updated_at_state.row_fetch_completed
                    && updated_at_state.result_kind.is_none()
                {
                    updated_at_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableSingleColumnProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }

                apply_direct_immutable_single_column_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase,
                    &phase_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_single_column_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_single_column_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);

                if phase_state.is_conclusive() && updated_at_state.is_conclusive() {
                    diagnostic
                        .checkpoint_row_fetch_direct_immutable_single_column_probe_reason_class =
                        CheckpointRowFetchDirectImmutableSingleColumnProbeReasonClass::CheckpointRowFetchDirectImmutableSingleColumnProbeProven;
                    diagnostic
                        .checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                        format!(
                            "direct immutable single-column projection split probe completed with bounded outcomes: {} {}",
                            summarize_direct_immutable_single_column_subprobe(
                                "phase_select",
                                phase_state.result_kind
                            ),
                            summarize_direct_immutable_single_column_subprobe(
                                "updated_at_select",
                                updated_at_state.result_kind
                            )
                        );
                } else {
                    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_budget_exhausted =
                        true;
                    diagnostic
                        .checkpoint_row_fetch_direct_immutable_single_column_probe_reason_class =
                        CheckpointRowFetchDirectImmutableSingleColumnProbeReasonClass::CheckpointRowFetchDirectImmutableSingleColumnProbeBudgetExhausted;
                    diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_stage =
                        Some(resolve_direct_immutable_single_column_unfinished_stage(
                            &phase_state,
                            &updated_at_state,
                        ));
                    diagnostic
                        .checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                        format!(
                            "checkpoint row-fetch direct immutable single-column probe exhausted its bounded budget before both subprobes reached conclusive outcomes: {} {}",
                            summarize_direct_immutable_single_column_subprobe(
                                "phase_select",
                                phase_state.result_kind
                            ),
                            summarize_direct_immutable_single_column_subprobe(
                                "updated_at_select",
                                updated_at_state.result_kind
                            )
                        );
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                apply_direct_immutable_single_column_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableSingleColumnTarget::Phase,
                    &phase_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_single_column_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableSingleColumnTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_single_column_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_single_column_probe_reason_class =
                    CheckpointRowFetchDirectImmutableSingleColumnProbeReasonClass::CheckpointRowFetchDirectImmutableSingleColumnProbeUnprovenDueToMissingEvidence;
                diagnostic
                    .checkpoint_row_fetch_direct_immutable_single_column_probe_explanation =
                    "checkpoint row-fetch direct immutable single-column probe workers disconnected before returning conclusive outcomes"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

fn probe_checkpoint_row_fetch_minimal_snapshot_read_only(
    config_path: &Path,
) -> CheckpointRowFetchMinimalSnapshotProbeDiagnostic {
    probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget_impl(
        config_path,
        StdDuration::from_millis(DEFAULT_CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_BUDGET_MS),
        #[cfg(test)]
        None,
    )
}

#[cfg(test)]
fn probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget(
    config_path: &Path,
    budget: StdDuration,
) -> CheckpointRowFetchMinimalSnapshotProbeDiagnostic {
    probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget_impl(
        config_path,
        budget,
        None,
    )
}

#[cfg(test)]
fn probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget_and_test_behavior(
    config_path: &Path,
    budget: StdDuration,
    test_behavior: Option<CheckpointRowFetchMinimalSnapshotProbeTestBehavior>,
) -> CheckpointRowFetchMinimalSnapshotProbeDiagnostic {
    probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget_impl(
        config_path,
        budget,
        test_behavior,
    )
}

fn probe_checkpoint_row_fetch_minimal_snapshot_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchMinimalSnapshotProbeTestBehavior>,
) -> CheckpointRowFetchMinimalSnapshotProbeDiagnostic {
    let mut diagnostic = CheckpointRowFetchMinimalSnapshotProbeDiagnostic::unproven(
        config_path,
        "checkpoint row-fetch minimal-snapshot probe did not run".to_string(),
    );
    diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_BUDGET_SOURCE.to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_observed = true;

    let (tx, rx) = mpsc::sync_channel(16);
    let config_path_for_worker = config_path.to_path_buf();
    let runtime_db_path_for_worker = runtime_db_path.clone();
    thread::spawn(move || {
        let _ = probe_checkpoint_row_fetch_minimal_snapshot_worker(
            &config_path_for_worker,
            &runtime_db_path_for_worker,
            budget,
            tx,
            #[cfg(test)]
            test_behavior,
        );
    });

    let mut current_stage = CheckpointRowFetchMinimalSnapshotProbeStage::CreateTempDir;
    loop {
        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::TempDirCreated { path }) => {
                current_stage = CheckpointRowFetchMinimalSnapshotProbeStage::CreateTempDir;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_temp_dir = Some(path);
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::SqliteSideMaterializationStarted {
                    source_size_bytes,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_main_db_source_size_bytes =
                    Some(source_size_bytes);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_sqlite_side_materialization_attempted = true;
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                    event,
                    elapsed_ms,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                apply_minimal_snapshot_materialization_event(
                    &mut diagnostic,
                    event,
                    elapsed_ms,
                );
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectMetadata {
                    explain_query_plan,
                    explain_query_plan_rows,
                    connection_journal_mode,
                    connection_locking_mode,
                    connection_query_only,
                    busy_timeout_ms,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_explain_query_plan =
                    Some(explain_query_plan);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_explain_query_plan_rows =
                    Some(explain_query_plan_rows);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_connection_journal_mode =
                    Some(connection_journal_mode);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_connection_locking_mode =
                    Some(connection_locking_mode);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_connection_query_only =
                    Some(connection_query_only);
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_busy_timeout_ms =
                    Some(busy_timeout_ms);
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectExecuteCompleted {
                    elapsed_ms,
                    rows_changed,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_execute_completed =
                    true;
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_execute_elapsed_ms =
                    elapsed_ms;
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_rows_changed =
                    Some(rows_changed);
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectPostcheckCompleted {
                    row_count,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_postcheck_row_count =
                    Some(row_count);
            }
            Ok(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::SqliteSideMaterializationCompleted {
                    bytes_copied,
                    elapsed_ms,
                },
            ) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::SqliteSideMaterialization;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_main_db_bytes_copied =
                    bytes_copied;
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_sqlite_side_materialization_completed = true;
                diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_sqlite_side_materialization_elapsed_ms =
                    elapsed_ms;
            }
            Ok(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::HandoffStarted) => {
                current_stage =
                    CheckpointRowFetchMinimalSnapshotProbeStage::HandoffToZeroTimeoutProbe;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
            }
            Ok(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::Finished(Ok(base))) => {
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_runtime_db_opened_read_only =
                    base.checkpoint_row_fetch_busy_probe_runtime_db_opened_read_only;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_budget_exhausted =
                    base.checkpoint_row_fetch_busy_probe_budget_exhausted;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    base.checkpoint_row_fetch_busy_probe_stage;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_connection_journal_mode =
                    base.checkpoint_row_fetch_busy_probe_connection_journal_mode;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_connection_locking_mode =
                    base.checkpoint_row_fetch_busy_probe_connection_locking_mode;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_connection_query_only =
                    base.checkpoint_row_fetch_busy_probe_connection_query_only;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_query_readonly_mode =
                    base.checkpoint_row_fetch_busy_probe_query_readonly_mode;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_busy_timeout_ms_before =
                    base.checkpoint_row_fetch_busy_probe_busy_timeout_ms_before;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_busy_timeout_ms_applied =
                    base.checkpoint_row_fetch_busy_probe_busy_timeout_ms_applied;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_query_sql =
                    base.checkpoint_row_fetch_busy_probe_query_sql;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explain_query_plan =
                    base.checkpoint_row_fetch_busy_probe_explain_query_plan;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explain_query_plan_rows =
                    base.checkpoint_row_fetch_busy_probe_explain_query_plan_rows;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_access_path =
                    base.checkpoint_row_fetch_busy_probe_access_path;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_step_started =
                    base.checkpoint_row_fetch_busy_probe_step_started;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_step_completed =
                    base.checkpoint_row_fetch_busy_probe_step_completed;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_step_elapsed_ms =
                    base.checkpoint_row_fetch_busy_probe_step_elapsed_ms;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_result_kind =
                    base.checkpoint_row_fetch_busy_probe_result_kind;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_sqlite_error_code =
                    base.checkpoint_row_fetch_busy_probe_sqlite_error_code;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_sqlite_error_message =
                    base.checkpoint_row_fetch_busy_probe_sqlite_error_message;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_row_returned =
                    base.checkpoint_row_fetch_busy_probe_row_returned;

                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_reason_class =
                    match diagnostic
                        .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                    {
                        CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::ApplicationLevelSourceRowFetch => {
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeStrategyStillSourceRowFetchDependent
                        }
                        CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::SqliteEngineSideMaterialization
                        | CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::SourceRowFetchIndependent => {
                            match base.checkpoint_row_fetch_busy_probe_reason_class {
                                CheckpointRowFetchBusyProbeReasonClass::CheckpointRowFetchBusyProbeProvenNonBusyWait => {
                                    CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeProvenNonBusyWait
                                }
                                CheckpointRowFetchBusyProbeReasonClass::CheckpointRowFetchBusyProbeProvenBusyWait => {
                                    CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeProvenBusyWait
                                }
                                CheckpointRowFetchBusyProbeReasonClass::CheckpointRowFetchBusyProbeBudgetExhausted => {
                                    CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeBudgetExhausted
                                }
                                CheckpointRowFetchBusyProbeReasonClass::CheckpointRowFetchBusyProbeUnprovenDueToMissingEvidence => {
                                    CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeUnprovenDueToMissingEvidence
                                }
                            }
                        }
                    };
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explanation =
                    if diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_reason_class
                        == CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeStrategyStillSourceRowFetchDependent
                    {
                        format!(
                            "minimal-snapshot strategy={} still depends on an application-level live source row fetch before temp snapshot handoff; dependency_kind={}, source_row_fetch_attempted={}, source_row_fetch_completed={}, downstream_probe_reason_class={}",
                            CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                            serde_json::to_string(
                                &diagnostic
                                    .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                            )
                            .unwrap_or_else(|_| "\"unknown\"".to_string())
                            .trim_matches('"'),
                            diagnostic
                                .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_attempted,
                            diagnostic
                                .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_completed,
                            serde_json::to_string(&base.checkpoint_row_fetch_busy_probe_reason_class)
                                .unwrap_or_else(|_| "\"unknown\"".to_string())
                                .trim_matches('"')
                        )
                    } else {
                        match diagnostic
                            .checkpoint_row_fetch_minimal_snapshot_probe_reason_class
                        {
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeProvenNonBusyWait => {
                                format!(
                                    "minimal-snapshot zero-busy-timeout checkpoint row fetch completed without SQLITE_BUSY or SQLITE_LOCKED ({}) using strategy={} dependency_kind={}",
                                    diagnostic
                                        .checkpoint_row_fetch_minimal_snapshot_probe_result_kind
                                        .as_ref()
                                        .map(|kind| serde_json::to_string(kind).unwrap_or_else(|_| "\"unknown\"".to_string()).trim_matches('\"').to_string())
                                        .unwrap_or_else(|| "unknown".to_string()),
                                    CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                                    serde_json::to_string(
                                        &diagnostic
                                            .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                                    )
                                    .unwrap_or_else(|_| "\"unknown\"".to_string())
                                    .trim_matches('"')
                                )
                            }
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeProvenBusyWait => {
                                format!(
                                    "minimal-snapshot zero-busy-timeout checkpoint row fetch returned {} at the SQLite step boundary using strategy={} dependency_kind={}",
                                    diagnostic
                                        .checkpoint_row_fetch_minimal_snapshot_probe_sqlite_error_code
                                        .as_deref()
                                        .unwrap_or("SQLITE_BUSY_OR_LOCKED"),
                                    CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                                    serde_json::to_string(
                                        &diagnostic
                                            .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                                    )
                                    .unwrap_or_else(|_| "\"unknown\"".to_string())
                                    .trim_matches('"')
                                )
                            }
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeBudgetExhausted => {
                                format!(
                                    "minimal-snapshot checkpoint row-fetch probe exhausted its bounded budget while executing stage={} using strategy={} dependency_kind={}",
                                    diagnostic
                                        .checkpoint_row_fetch_minimal_snapshot_probe_stage
                                        .as_deref()
                                        .unwrap_or("unknown"),
                                    CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                                    serde_json::to_string(
                                        &diagnostic
                                            .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                                    )
                                    .unwrap_or_else(|_| "\"unknown\"".to_string())
                                    .trim_matches('"')
                                )
                            }
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeUnprovenDueToMissingEvidence => {
                                base.checkpoint_row_fetch_busy_probe_explanation
                            }
                            CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeStrategyStillSourceRowFetchDependent => {
                                unreachable!()
                            }
                        }
                    };
                return diagnostic;
            }
            Ok(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::Finished(Err(error))) => {
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explanation = error;
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_budget_exhausted = true;
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_reason_class = match diagnostic
                    .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                {
                    CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::ApplicationLevelSourceRowFetch => {
                        CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeStrategyStillSourceRowFetchDependent
                    }
                    CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::SqliteEngineSideMaterialization
                    | CheckpointRowFetchMinimalSnapshotProbeSourceRowFetchDependencyKind::SourceRowFetchIndependent => {
                        CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeBudgetExhausted
                    }
                };
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explanation =
                    if diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_reason_class
                        == CheckpointRowFetchMinimalSnapshotProbeReasonClass::CheckpointRowFetchMinimalSnapshotProbeStrategyStillSourceRowFetchDependent
                    {
                        format!(
                            "minimal-snapshot strategy={} is still source-row-fetch dependent; dependency_kind={}, operator exhausted its bounded budget while executing stage={}, source_row_fetch_attempted={}, source_row_fetch_completed={}",
                            CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                            serde_json::to_string(
                                &diagnostic
                                    .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                            )
                            .unwrap_or_else(|_| "\"unknown\"".to_string())
                            .trim_matches('"'),
                            current_stage.as_str(),
                            diagnostic
                                .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_attempted,
                            diagnostic
                                .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_completed
                        )
                    } else {
                        format!(
                            "minimal-snapshot checkpoint row-fetch probe exhausted its bounded budget while executing stage={} using strategy={} dependency_kind={} last_materialization_event={}",
                            current_stage.as_str(),
                            CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_PROBE_STRATEGY,
                            serde_json::to_string(
                                &diagnostic
                                    .checkpoint_row_fetch_minimal_snapshot_probe_source_row_fetch_dependency_kind
                            )
                            .unwrap_or_else(|_| "\"unknown\"".to_string())
                            .trim_matches('"'),
                            diagnostic
                                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_last_event
                                .as_deref()
                                .unwrap_or("null")
                        )
                    };
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_explanation =
                    "minimal-snapshot checkpoint row-fetch probe worker disconnected before returning a result".to_string();
                return diagnostic;
            }
        }
    }
}

