fn probe_checkpoint_row_fetch_materialization_busy_wait_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchMaterializationBusyProbeTestBehavior>,
) -> CheckpointRowFetchMaterializationBusyProbeDiagnostic {
    let mut diagnostic = CheckpointRowFetchMaterializationBusyProbeDiagnostic::unproven(
        config_path,
        "checkpoint row-fetch materialization busy probe did not run".to_string(),
    );
    diagnostic.checkpoint_row_fetch_materialization_busy_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_materialization_busy_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_MATERIALIZATION_BUSY_PROBE_BUDGET_SOURCE.to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_materialization_busy_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_materialization_busy_probe_observed = true;

    let (tx, rx) = mpsc::sync_channel(32);
    let config_path_for_worker = config_path.to_path_buf();
    let runtime_db_path_for_worker = runtime_db_path.clone();
    thread::spawn(move || {
        let _ = probe_checkpoint_row_fetch_materialization_busy_wait_worker(
            &config_path_for_worker,
            &runtime_db_path_for_worker,
            tx,
            #[cfg(test)]
            test_behavior,
        );
    });

    let mut current_stage = CheckpointRowFetchMaterializationBusyProbeStage::CreateTempDir;
    loop {
        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::TempDirCreated {
                path,
            }) => {
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_temp_dir = Some(path);
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(stage)) => {
                current_stage = stage;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(stage.as_str().to_string());
                if stage == CheckpointRowFetchMaterializationBusyProbeStage::InsertSelectExecute {
                    diagnostic
                        .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_execute_started =
                        true;
                }
                if stage == CheckpointRowFetchMaterializationBusyProbeStage::Postcheck {
                    diagnostic
                        .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_postcheck_started =
                        true;
                }
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::BusyTimeoutBefore(value)) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::LoadBusyTimeoutBefore;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_busy_timeout_ms_before =
                    Some(value);
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::BusyTimeoutApplied(value)) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::ApplyBusyTimeoutZero;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_busy_timeout_ms_applied =
                    Some(value);
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::ConnectionReadMode {
                journal_mode,
                locking_mode,
                query_only,
            }) => {
                current_stage =
                    CheckpointRowFetchMaterializationBusyProbeStage::LoadConnectionMetadata;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_connection_journal_mode =
                    Some(journal_mode);
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_connection_locking_mode =
                    Some(locking_mode);
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_connection_query_only =
                    Some(query_only);
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::QueryPlan {
                explain_query_plan,
                explain_query_plan_rows,
            }) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::LoadExplainQueryPlan;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_explain_query_plan =
                    Some(explain_query_plan);
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_explain_query_plan_rows =
                    Some(explain_query_plan_rows);
            }
            Ok(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteStarted,
            ) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::InsertSelectExecute;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_execute_started =
                    true;
            }
            Ok(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteCompleted {
                    elapsed_ms,
                    rows_changed,
                    result_kind,
                    sqlite_error_code,
                    sqlite_error_message,
                },
            ) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::InsertSelectExecute;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_execute_completed =
                    true;
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_execute_elapsed_ms =
                    elapsed_ms;
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_rows_changed =
                    Some(rows_changed);
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_result_kind =
                    Some(result_kind);
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_sqlite_error_code =
                    sqlite_error_code;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_sqlite_error_message =
                    sqlite_error_message;
            }
            Ok(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectPostcheckStarted,
            ) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::Postcheck;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_postcheck_started =
                    true;
            }
            Ok(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectPostcheckCompleted {
                    row_count,
                },
            ) => {
                current_stage = CheckpointRowFetchMaterializationBusyProbeStage::Postcheck;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_postcheck_completed =
                    true;
                diagnostic
                    .checkpoint_row_fetch_materialization_busy_probe_materialization_insert_select_postcheck_row_count =
                    Some(row_count);
            }
            Ok(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(result)) => {
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                match result {
                    Ok(()) => {
                        diagnostic.checkpoint_row_fetch_materialization_busy_probe_reason_class =
                            match diagnostic
                                .checkpoint_row_fetch_materialization_busy_probe_result_kind
                            {
                                Some(
                                    CheckpointRowFetchMaterializationBusyProbeResultKind::InsertSelectSucceeded,
                                ) => CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeProvenNonBusyWait,
                                Some(
                                    CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteBusy
                                    | CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteLocked,
                                ) => CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeProvenBusyWait,
                                Some(
                                    CheckpointRowFetchMaterializationBusyProbeResultKind::OtherSqliteError
                                    | CheckpointRowFetchMaterializationBusyProbeResultKind::OtherError,
                                )
                                | None => CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeUnprovenDueToMissingEvidence,
                            };
                        diagnostic.checkpoint_row_fetch_materialization_busy_probe_explanation =
                            match diagnostic
                                .checkpoint_row_fetch_materialization_busy_probe_reason_class
                            {
                                CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeProvenNonBusyWait => {
                                    format!(
                                        "zero-busy-timeout materialization INSERT ... SELECT completed without SQLITE_BUSY or SQLITE_LOCKED using strategy={}",
                                        CHECKPOINT_ROW_FETCH_MATERIALIZATION_BUSY_PROBE_STRATEGY
                                    )
                                }
                                CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeProvenBusyWait => {
                                    format!(
                                        "zero-busy-timeout materialization INSERT ... SELECT returned {} using strategy={}",
                                        diagnostic
                                            .checkpoint_row_fetch_materialization_busy_probe_sqlite_error_code
                                            .as_deref()
                                            .unwrap_or("SQLITE_BUSY_OR_LOCKED"),
                                        CHECKPOINT_ROW_FETCH_MATERIALIZATION_BUSY_PROBE_STRATEGY
                                    )
                                }
                                CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeBudgetExhausted => unreachable!(),
                                CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeUnprovenDueToMissingEvidence => {
                                    diagnostic
                                        .checkpoint_row_fetch_materialization_busy_probe_sqlite_error_message
                                        .clone()
                                        .unwrap_or_else(|| {
                                            "materialization busy probe ended without a conclusive result".to_string()
                                        })
                                }
                            };
                    }
                    Err(error) => {
                        diagnostic.checkpoint_row_fetch_materialization_busy_probe_reason_class =
                            CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeUnprovenDueToMissingEvidence;
                        diagnostic.checkpoint_row_fetch_materialization_busy_probe_explanation =
                            error;
                    }
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_budget_exhausted = true;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_reason_class =
                    CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeBudgetExhausted;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_stage =
                    Some(current_stage.as_str().to_string());
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_explanation = format!(
                    "checkpoint row-fetch materialization busy probe exhausted its bounded budget while executing stage={}",
                    current_stage.as_str()
                );
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_reason_class =
                    CheckpointRowFetchMaterializationBusyProbeReasonClass::CheckpointRowFetchMaterializationBusyProbeUnprovenDueToMissingEvidence;
                diagnostic.checkpoint_row_fetch_materialization_busy_probe_explanation =
                    "checkpoint row-fetch materialization busy probe worker disconnected before returning a result"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

fn apply_minimal_snapshot_materialization_event(
    diagnostic: &mut CheckpointRowFetchMinimalSnapshotProbeDiagnostic,
    event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent,
    elapsed_ms: u64,
) {
    diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_materialization_event_count = diagnostic
        .checkpoint_row_fetch_minimal_snapshot_probe_materialization_event_count
        .saturating_add(1);
    diagnostic.checkpoint_row_fetch_minimal_snapshot_probe_materialization_last_event =
        Some(event.as_str().to_string());
    match event {
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::TempDbOpenStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_temp_db_open_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::TempDbOpenCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_temp_db_open_completed =
                true;
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_temp_db_open_elapsed_ms =
                elapsed_ms;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::SchemaCreateStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_schema_create_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::SchemaCreateCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_schema_create_completed =
                true;
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_schema_create_elapsed_ms =
                elapsed_ms;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::AttachStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_attach_started = true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::AttachCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_attach_completed =
                true;
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_attach_elapsed_ms =
                elapsed_ms;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectExecuteStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_execute_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_completed =
                true;
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_elapsed_ms =
                elapsed_ms;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectPostcheckStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_postcheck_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectPostcheckCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_insert_select_postcheck_completed =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::DetachStarted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_detach_started =
                true;
        }
        CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::DetachCompleted => {
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_detach_completed =
                true;
            diagnostic
                .checkpoint_row_fetch_minimal_snapshot_probe_materialization_detach_elapsed_ms =
                elapsed_ms;
        }
    }
}

fn create_checkpoint_row_fetch_probe_temp_dir() -> Result<PathBuf> {
    let base = env::temp_dir();
    for attempt in 0..32_u32 {
        let candidate = base.join(format!(
            "checkpoint-row-fetch-copied-snapshot-probe-{}-{}-{}",
            std::process::id(),
            Utc::now().timestamp_millis(),
            attempt
        ));
        match fs::create_dir(&candidate) {
            Ok(()) => return Ok(candidate),
            Err(error) if error.kind() == std::io::ErrorKind::AlreadyExists => continue,
            Err(error) => {
                return Err(error).with_context(|| {
                    format!(
                        "failed creating copied-snapshot checkpoint row-fetch probe temp dir {}",
                        candidate.display()
                    )
                });
            }
        }
    }
    bail!("failed creating a unique copied-snapshot checkpoint row-fetch probe temp dir")
}

fn sqlite_sidecar_path(base: &Path, suffix: &str) -> PathBuf {
    let mut sidecar = base.as_os_str().to_os_string();
    sidecar.push(suffix);
    PathBuf::from(sidecar)
}

fn compute_bytes_per_second(bytes: u64, elapsed_ms: u64) -> u64 {
    if bytes == 0 {
        return 0;
    }
    let elapsed_ms = elapsed_ms.max(1);
    ((bytes as u128) * 1_000 / (elapsed_ms as u128)).min(u64::MAX as u128) as u64
}

fn finalize_copy_main_progress_kind(
    diagnostic: &mut CheckpointRowFetchCopiedSnapshotProbeDiagnostic,
) {
    if diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_completed {
        diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_progress_kind =
            Some(CheckpointRowFetchCopiedSnapshotProbeCopyMainProgressKind::FullCopyCompleted);
        if diagnostic
            .checkpoint_row_fetch_copied_snapshot_probe_copy_main_effective_bytes_per_sec
            .is_none()
        {
            diagnostic
                .checkpoint_row_fetch_copied_snapshot_probe_copy_main_effective_bytes_per_sec =
                Some(compute_bytes_per_second(
                    diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_bytes,
                    diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_elapsed_ms,
                ));
        }
        return;
    }
    if !diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_started {
        return;
    }
    diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_progress_kind = Some(
        if diagnostic
            .checkpoint_row_fetch_copied_snapshot_probe_copy_main_bytes_observed_before_timeout
            == 0
        {
            CheckpointRowFetchCopiedSnapshotProbeCopyMainProgressKind::NoBytesObservedBeforeTimeout
        } else {
            CheckpointRowFetchCopiedSnapshotProbeCopyMainProgressKind::PartialCopyObservedBeforeTimeout
        },
    );
    if diagnostic
        .checkpoint_row_fetch_copied_snapshot_probe_copy_main_effective_bytes_per_sec
        .is_none()
    {
        diagnostic
            .checkpoint_row_fetch_copied_snapshot_probe_copy_main_effective_bytes_per_sec =
            Some(compute_bytes_per_second(
                diagnostic
                    .checkpoint_row_fetch_copied_snapshot_probe_copy_main_bytes_observed_before_timeout,
                diagnostic.checkpoint_row_fetch_copied_snapshot_probe_copy_main_elapsed_ms,
            ));
    }
}

fn copy_checkpoint_row_fetch_probe_file(src: &Path, dst: &Path) -> Result<Option<u64>> {
    if !src.exists() {
        return Ok(None);
    }
    let copied_bytes = fs::copy(src, dst).with_context(|| {
        format!(
            "failed copying checkpoint row-fetch probe file {} -> {}",
            src.display(),
            dst.display()
        )
    })?;
    Ok(Some(copied_bytes))
}

fn copy_checkpoint_row_fetch_probe_main_file_with_progress(
    src: &Path,
    dst: &Path,
    tx: &mpsc::SyncSender<CheckpointRowFetchCopiedSnapshotProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchCopiedSnapshotProbeTestBehavior>,
) -> Result<(u64, u64)> {
    let mut src_file = File::open(src).with_context(|| {
        format!(
            "failed opening checkpoint row-fetch copied-snapshot main db source {}",
            src.display()
        )
    })?;
    let mut dst_file = File::create(dst).with_context(|| {
        format!(
            "failed opening checkpoint row-fetch copied-snapshot main db destination {}",
            dst.display()
        )
    })?;
    let mut buffer = [0_u8; 256 * 1024];
    let mut total_bytes = 0_u64;
    let copy_started_at = Instant::now();
    #[cfg(test)]
    let mut delayed_after_first_chunk = false;
    loop {
        #[cfg(test)]
        if total_bytes == 0 {
            if let Some(CheckpointRowFetchCopiedSnapshotProbeTestBehavior::DelayBeforeCopyMain(
                delay,
            )) = test_behavior
            {
                thread::sleep(delay);
            }
        }
        let read_len = src_file.read(&mut buffer).with_context(|| {
            format!(
                "failed reading checkpoint row-fetch copied-snapshot main db source {}",
                src.display()
            )
        })?;
        if read_len == 0 {
            break;
        }
        dst_file.write_all(&buffer[..read_len]).with_context(|| {
            format!(
                "failed writing checkpoint row-fetch copied-snapshot main db destination {}",
                dst.display()
            )
        })?;
        total_bytes = total_bytes.saturating_add(read_len as u64);
        let _ = tx.try_send(
            CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyMainProgress {
                bytes_copied: total_bytes,
                elapsed_ms: elapsed_ms(copy_started_at),
            },
        );
        #[cfg(test)]
        if !delayed_after_first_chunk {
            if let Some(
                CheckpointRowFetchCopiedSnapshotProbeTestBehavior::DelayAfterCopyMainFirstChunk(
                    delay,
                ),
            ) = test_behavior
            {
                delayed_after_first_chunk = true;
                thread::sleep(delay);
            }
        }
    }
    dst_file.flush().with_context(|| {
        format!(
            "failed flushing checkpoint row-fetch copied-snapshot main db destination {}",
            dst.display()
        )
    })?;
    Ok((total_bytes, elapsed_ms(copy_started_at)))
}

fn probe_checkpoint_row_fetch_copied_snapshot_worker(
    config_path: &Path,
    runtime_db_path: &Path,
    budget: StdDuration,
    tx: mpsc::SyncSender<CheckpointRowFetchCopiedSnapshotProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchCopiedSnapshotProbeTestBehavior>,
) -> Result<()> {
    let total_started_at = Instant::now();
    let run = || -> Result<()> {
        let temp_dir_started_at = Instant::now();
        let temp_dir_path = create_checkpoint_row_fetch_probe_temp_dir()?;
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::TempDirCreated {
                    path: temp_dir_path.display().to_string(),
                    elapsed_ms: elapsed_ms(temp_dir_started_at),
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let copied_main_db_path = temp_dir_path.join(
            runtime_db_path
                .file_name()
                .unwrap_or_else(|| std::ffi::OsStr::new("runtime.db")),
        );

        let runtime_db_meta = fs::metadata(runtime_db_path).with_context(|| {
            format!(
                "failed reading runtime db metadata for copied-snapshot checkpoint row-fetch probe {}",
                runtime_db_path.display()
            )
        })?;
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyMainStarted {
                    source_size_bytes: runtime_db_meta.len(),
                    source_modified_at: runtime_db_meta.modified().ok().map(DateTime::<Utc>::from),
                    started_at_unix_ms: Utc::now().timestamp_millis().max(0) as u64,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let (main_copy_bytes, copy_main_elapsed_ms) =
            match copy_checkpoint_row_fetch_probe_main_file_with_progress(
                runtime_db_path,
                &copied_main_db_path,
                &tx,
                #[cfg(test)]
                test_behavior,
            ) {
                Ok(result) => result,
                Err(_error) if !runtime_db_path.exists() => {
                    bail!(
                    "runtime db {} did not exist for copied-snapshot checkpoint row-fetch probe",
                    runtime_db_path.display()
                );
                }
                Err(error) => return Err(error),
            };
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyMainCompleted {
                    bytes: main_copy_bytes,
                    elapsed_ms: copy_main_elapsed_ms,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let runtime_db_wal_path = sqlite_sidecar_path(runtime_db_path, "-wal");
        let copied_wal_path = sqlite_sidecar_path(&copied_main_db_path, "-wal");
        if tx
            .send(CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyWalStarted)
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        if let Some(CheckpointRowFetchCopiedSnapshotProbeTestBehavior::DelayBeforeCopyWal(delay)) =
            test_behavior
        {
            thread::sleep(delay);
        }
        let copy_wal_started_at = Instant::now();
        let wal_copy =
            copy_checkpoint_row_fetch_probe_file(&runtime_db_wal_path, &copied_wal_path)?;
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyWalCompleted {
                    copied: wal_copy.is_some(),
                    bytes: wal_copy.unwrap_or(0),
                    elapsed_ms: elapsed_ms(copy_wal_started_at),
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let runtime_db_shm_path = sqlite_sidecar_path(runtime_db_path, "-shm");
        let copied_shm_path = sqlite_sidecar_path(&copied_main_db_path, "-shm");
        if tx
            .send(CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyShmStarted)
            .is_err()
        {
            return Ok(());
        }
        let copy_shm_started_at = Instant::now();
        let shm_copy =
            copy_checkpoint_row_fetch_probe_file(&runtime_db_shm_path, &copied_shm_path)?;
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::CopyShmCompleted {
                    copied: shm_copy.is_some(),
                    bytes: shm_copy.unwrap_or(0),
                    elapsed_ms: elapsed_ms(copy_shm_started_at),
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::HandoffStarted)
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        if let Some(CheckpointRowFetchCopiedSnapshotProbeTestBehavior::DelayBeforeHandoff(delay)) =
            test_behavior
        {
            thread::sleep(delay);
        }
        let handoff_started_at = Instant::now();
        let remaining_budget = remaining_budget_duration(budget, total_started_at);
        #[cfg(test)]
        let busy_probe_test_behavior = match test_behavior {
            Some(CheckpointRowFetchCopiedSnapshotProbeTestBehavior::BusyProbe(inner)) => {
                Some(inner)
            }
            _ => None,
        };
        let base = probe_checkpoint_row_fetch_busy_wait_against_db_path_with_budget(
            config_path,
            &copied_main_db_path,
            remaining_budget,
            #[cfg(test)]
            busy_probe_test_behavior,
        );
        if tx
            .send(
                CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::HandoffCompleted {
                    elapsed_ms: elapsed_ms(handoff_started_at),
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::Finished(Ok(base)));
        Ok(())
    };

    if let Err(error) = run() {
        let _ = tx.send(
            CheckpointRowFetchCopiedSnapshotProbeWorkerMessage::Finished(Err(format!("{error:#}"))),
        );
    }
    Ok(())
}

fn create_checkpoint_row_fetch_minimal_snapshot_db_via_sqlite_materialization(
    runtime_db_path: &Path,
    snapshot_db_path: &Path,
    tx: &mpsc::SyncSender<CheckpointRowFetchMinimalSnapshotProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchMinimalSnapshotProbeTestBehavior>,
) -> Result<(u64, u64)> {
    #[cfg(test)]
    if let Some(
        CheckpointRowFetchMinimalSnapshotProbeTestBehavior::DelayBeforeSqliteSideMaterialization(
            delay,
        ),
    ) = test_behavior
    {
        thread::sleep(delay);
    }

    let materialization_started_at = Instant::now();
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::TempDbOpenStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    let temp_db_open_started_at = Instant::now();
    let conn = Connection::open(snapshot_db_path).with_context(|| {
        format!(
            "failed opening minimal snapshot sqlite db {}",
            snapshot_db_path.display()
        )
    })?;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::TempDbOpenCompleted,
                elapsed_ms: elapsed_ms(temp_db_open_started_at),
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::SchemaCreateStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    let schema_create_started_at = Instant::now();
    conn.execute_batch(
        "PRAGMA journal_mode = DELETE;
         CREATE TABLE discovery_persisted_rebuild_state (
             id INTEGER PRIMARY KEY,
             phase TEXT,
             updated_at TEXT
         );",
    )
    .context("failed creating minimal snapshot row-meta sqlite schema")?;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::SchemaCreateCompleted,
                elapsed_ms: elapsed_ms(schema_create_started_at),
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::AttachStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    #[cfg(test)]
    if let Some(
        CheckpointRowFetchMinimalSnapshotProbeTestBehavior::DelayBeforeMaterializationAttach(delay),
    ) = test_behavior
    {
        thread::sleep(delay);
    }
    let attach_started_at = Instant::now();
    conn.execute(
        "ATTACH DATABASE ?1 AS source",
        [runtime_db_path.display().to_string()],
    )
    .with_context(|| {
        format!(
            "failed attaching source runtime db {} for minimal snapshot materialization",
            runtime_db_path.display()
        )
    })?;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::AttachCompleted,
                elapsed_ms: elapsed_ms(attach_started_at),
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    let insert_select_busy_timeout_ms = conn
        .query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
        .context(
            "failed reading sqlite busy_timeout for minimal snapshot insert-select materialization",
        )?;
    let insert_select_connection_journal_mode = conn
        .query_row("PRAGMA journal_mode", [], |row| row.get::<_, String>(0))
        .context(
            "failed reading sqlite journal_mode for minimal snapshot insert-select materialization",
        )?;
    let insert_select_connection_locking_mode = conn
        .query_row("PRAGMA locking_mode", [], |row| row.get::<_, String>(0))
        .context(
            "failed reading sqlite locking_mode for minimal snapshot insert-select materialization",
        )?;
    let insert_select_connection_query_only = conn
        .query_row("PRAGMA query_only", [], |row| row.get::<_, i64>(0))
        .context(
            "failed reading sqlite query_only for minimal snapshot insert-select materialization",
        )?
        != 0;
    let insert_select_explain_query_plan = load_explain_query_plan_for_sql(
        &conn,
        CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_SQLITE_SIDE_MATERIALIZATION_SQL,
        "minimal snapshot insert-select materialization",
    )?;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectMetadata {
                explain_query_plan: insert_select_explain_query_plan.explain_query_plan,
                explain_query_plan_rows: insert_select_explain_query_plan.explain_query_plan_rows,
                connection_journal_mode: insert_select_connection_journal_mode,
                connection_locking_mode: insert_select_connection_locking_mode,
                connection_query_only: insert_select_connection_query_only,
                busy_timeout_ms: insert_select_busy_timeout_ms,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectExecuteStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    #[cfg(test)]
    if let Some(
        CheckpointRowFetchMinimalSnapshotProbeTestBehavior::DelayBeforeMaterializationInsertSelect(
            delay,
        ),
    ) = test_behavior
    {
        thread::sleep(delay);
    }
    let insert_select_started_at = Instant::now();
    conn.execute(
        CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_SQLITE_SIDE_MATERIALIZATION_SQL,
        [],
    )
    .context("failed sqlite-side materialization of minimal snapshot row-meta")?;
    let insert_select_rows_changed = conn.changes();
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectExecuteCompleted {
                elapsed_ms: elapsed_ms(insert_select_started_at),
                rows_changed: insert_select_rows_changed,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectCompleted,
                elapsed_ms: elapsed_ms(insert_select_started_at),
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectPostcheckStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    #[cfg(test)]
    if let Some(
        CheckpointRowFetchMinimalSnapshotProbeTestBehavior::DelayBeforeMaterializationPostcheck(
            delay,
        ),
    ) = test_behavior
    {
        thread::sleep(delay);
    }
    let postcheck_row_count = conn
        .query_row(CHECKPOINT_HEADLINE_ROW_META_ROW_COUNT_SQL, [], |row| {
            row.get::<_, i64>(0)
        })
        .context("failed postcheck row count after minimal snapshot insert-select materialization")?
        .max(0) as u64;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationInsertSelectPostcheckCompleted {
                row_count: postcheck_row_count,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event:
                    CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::InsertSelectPostcheckCompleted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::DetachStarted,
                elapsed_ms: 0,
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    let detach_started_at = Instant::now();
    conn.execute_batch("DETACH DATABASE source;")
        .context("failed detaching source runtime db after minimal snapshot materialization")?;
    if tx
        .send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::MaterializationEvent {
                event: CheckpointRowFetchMinimalSnapshotProbeMaterializationEvent::DetachCompleted,
                elapsed_ms: elapsed_ms(detach_started_at),
            },
        )
        .is_err()
    {
        return Ok((0, 0));
    }
    drop(conn);
    let snapshot_size = fs::metadata(snapshot_db_path)
        .with_context(|| {
            format!(
                "failed reading minimal snapshot sqlite db metadata {}",
                snapshot_db_path.display()
            )
        })?
        .len();
    Ok((snapshot_size, elapsed_ms(materialization_started_at)))
}

fn probe_checkpoint_row_fetch_minimal_snapshot_worker(
    config_path: &Path,
    runtime_db_path: &Path,
    budget: StdDuration,
    tx: mpsc::SyncSender<CheckpointRowFetchMinimalSnapshotProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchMinimalSnapshotProbeTestBehavior>,
) -> Result<()> {
    let total_started_at = Instant::now();
    let run = || -> Result<()> {
        let temp_dir_path = create_checkpoint_row_fetch_probe_temp_dir()?;
        if tx
            .send(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::TempDirCreated {
                    path: temp_dir_path.display().to_string(),
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let source_size_bytes = fs::metadata(runtime_db_path)
            .with_context(|| {
                format!(
                    "failed reading runtime db metadata for minimal-snapshot checkpoint row-fetch probe {}",
                    runtime_db_path.display()
                )
            })?
            .len();
        if tx
            .send(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::SqliteSideMaterializationStarted {
                    source_size_bytes,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let minimal_db_path = temp_dir_path.join(
            runtime_db_path
                .file_name()
                .unwrap_or_else(|| std::ffi::OsStr::new("runtime.db")),
        );
        let (minimal_db_bytes, materialization_elapsed_ms) =
            create_checkpoint_row_fetch_minimal_snapshot_db_via_sqlite_materialization(
                runtime_db_path,
                &minimal_db_path,
                &tx,
                #[cfg(test)]
                test_behavior,
            )?;
        if tx
            .send(
                CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::SqliteSideMaterializationCompleted {
                    bytes_copied: minimal_db_bytes,
                    elapsed_ms: materialization_elapsed_ms,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::HandoffStarted)
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        if let Some(CheckpointRowFetchMinimalSnapshotProbeTestBehavior::DelayBeforeHandoff(delay)) =
            test_behavior
        {
            thread::sleep(delay);
        }

        let remaining_budget = remaining_budget_duration(budget, total_started_at);
        #[cfg(test)]
        let busy_probe_test_behavior = match test_behavior {
            Some(CheckpointRowFetchMinimalSnapshotProbeTestBehavior::BusyProbe(inner)) => {
                Some(inner)
            }
            _ => None,
        };
        let base = probe_checkpoint_row_fetch_busy_wait_against_db_path_with_budget(
            config_path,
            &minimal_db_path,
            remaining_budget,
            #[cfg(test)]
            busy_probe_test_behavior,
        );
        let _ = tx.send(CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::Finished(Ok(base)));
        Ok(())
    };

    if let Err(error) = run() {
        let _ = tx.send(
            CheckpointRowFetchMinimalSnapshotProbeWorkerMessage::Finished(Err(format!(
                "{error:#}"
            ))),
        );
    }
    Ok(())
}

fn probe_checkpoint_row_fetch_materialization_busy_wait_worker(
    _config_path: &Path,
    runtime_db_path: &Path,
    tx: mpsc::SyncSender<CheckpointRowFetchMaterializationBusyProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<CheckpointRowFetchMaterializationBusyProbeTestBehavior>,
) -> Result<()> {
    let run = || -> Result<()> {
        let temp_dir_path = create_checkpoint_row_fetch_probe_temp_dir()?;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::TempDirCreated {
                    path: temp_dir_path.display().to_string(),
                },
            )
            .is_err()
        {
            return Ok(());
        }

        let minimal_db_path = temp_dir_path.join(
            runtime_db_path
                .file_name()
                .unwrap_or_else(|| std::ffi::OsStr::new("runtime.db")),
        );

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::TempDbOpen,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        let conn = Connection::open(&minimal_db_path).with_context(|| {
            format!(
                "failed opening materialization busy probe temp sqlite db {}",
                minimal_db_path.display()
            )
        })?;

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::SchemaCreate,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        conn.execute_batch(
            "PRAGMA journal_mode = DELETE;
             CREATE TABLE discovery_persisted_rebuild_state (
                 id INTEGER PRIMARY KEY,
                 phase TEXT,
                 updated_at TEXT
             );",
        )
        .context("failed creating materialization busy probe temp sqlite schema")?;

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::AttachSource,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        conn.execute(
            "ATTACH DATABASE ?1 AS source",
            [runtime_db_path.display().to_string()],
        )
        .with_context(|| {
            format!(
                "failed attaching source runtime db {} for materialization busy probe",
                runtime_db_path.display()
            )
        })?;

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::LoadBusyTimeoutBefore,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        let busy_timeout_ms_before = conn
            .query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
            .context("failed reading sqlite busy_timeout before materialization busy probe")?;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::BusyTimeoutBefore(
                    busy_timeout_ms_before,
                ),
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::ApplyBusyTimeoutZero,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        conn.execute_batch("PRAGMA busy_timeout = 0")
            .context("failed applying PRAGMA busy_timeout = 0 for materialization busy probe")?;
        let busy_timeout_ms_applied = conn
            .query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
            .context("failed reading sqlite busy_timeout after applying zero-timeout materialization busy probe")?;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::BusyTimeoutApplied(
                    busy_timeout_ms_applied,
                ),
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::LoadConnectionMetadata,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        let journal_mode = conn
            .query_row("PRAGMA journal_mode", [], |row| row.get::<_, String>(0))
            .context("failed reading sqlite journal_mode for materialization busy probe")?;
        let locking_mode = conn
            .query_row("PRAGMA locking_mode", [], |row| row.get::<_, String>(0))
            .context("failed reading sqlite locking_mode for materialization busy probe")?;
        let query_only = conn
            .query_row("PRAGMA query_only", [], |row| row.get::<_, i64>(0))
            .context("failed reading sqlite query_only for materialization busy probe")?
            != 0;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::ConnectionReadMode {
                    journal_mode,
                    locking_mode,
                    query_only,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::LoadExplainQueryPlan,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        let explain_query_plan = load_explain_query_plan_for_sql(
            &conn,
            CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_SQLITE_SIDE_MATERIALIZATION_SQL,
            "materialization busy probe insert-select",
        )?;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::QueryPlan {
                    explain_query_plan: explain_query_plan.explain_query_plan,
                    explain_query_plan_rows: explain_query_plan.explain_query_plan_rows,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::InsertSelectExecute,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteStarted,
            )
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        match test_behavior {
            Some(CheckpointRowFetchMaterializationBusyProbeTestBehavior::ForceBusy) => {
                let _ = tx.send(
                    CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteCompleted {
                        elapsed_ms: 0,
                        rows_changed: 0,
                        result_kind:
                            CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteBusy,
                        sqlite_error_code: Some("SQLITE_BUSY".to_string()),
                        sqlite_error_message: Some(
                            "forced SQLITE_BUSY at materialization INSERT ... SELECT boundary"
                                .to_string(),
                        ),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(Ok(())),
                );
                return Ok(());
            }
            Some(CheckpointRowFetchMaterializationBusyProbeTestBehavior::ForceLocked) => {
                let _ = tx.send(
                    CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteCompleted {
                        elapsed_ms: 0,
                        rows_changed: 0,
                        result_kind:
                            CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteLocked,
                        sqlite_error_code: Some("SQLITE_LOCKED".to_string()),
                        sqlite_error_message: Some(
                            "forced SQLITE_LOCKED at materialization INSERT ... SELECT boundary"
                                .to_string(),
                        ),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(Ok(())),
                );
                return Ok(());
            }
            Some(CheckpointRowFetchMaterializationBusyProbeTestBehavior::DelayBeforeExecute(
                delay,
            )) => {
                thread::sleep(delay);
            }
            Some(CheckpointRowFetchMaterializationBusyProbeTestBehavior::DelayBeforePostcheck(
                _,
            ))
            | None => {}
        }
        let execute_started_at = Instant::now();
        let execute_outcome = match conn.execute(
            CHECKPOINT_ROW_FETCH_MINIMAL_SNAPSHOT_SQLITE_SIDE_MATERIALIZATION_SQL,
            [],
        ) {
            Ok(_) => (
                CheckpointRowFetchMaterializationBusyProbeResultKind::InsertSelectSucceeded,
                conn.changes(),
                None,
                None,
            ),
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                let result_kind = match error.code {
                    ErrorCode::DatabaseBusy => {
                        CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteBusy
                    }
                    ErrorCode::DatabaseLocked => {
                        CheckpointRowFetchMaterializationBusyProbeResultKind::SqliteLocked
                    }
                    _ => CheckpointRowFetchMaterializationBusyProbeResultKind::OtherSqliteError,
                };
                (
                    result_kind,
                    0,
                    Some(sqlite_error_code_name(error.code)),
                    Some(message.unwrap_or_else(|| {
                        "sqlite failure at materialization INSERT ... SELECT boundary".to_string()
                    })),
                )
            }
            Err(error) => (
                CheckpointRowFetchMaterializationBusyProbeResultKind::OtherError,
                0,
                None,
                Some(error.to_string()),
            ),
        };
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectExecuteCompleted {
                    elapsed_ms: elapsed_ms(execute_started_at),
                    rows_changed: execute_outcome.1,
                    result_kind: execute_outcome.0,
                    sqlite_error_code: execute_outcome.2,
                    sqlite_error_message: execute_outcome.3,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        if execute_outcome.0
            != CheckpointRowFetchMaterializationBusyProbeResultKind::InsertSelectSucceeded
        {
            let _ =
                tx.send(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(Ok(())));
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Entered(
                    CheckpointRowFetchMaterializationBusyProbeStage::Postcheck,
                ),
            )
            .is_err()
        {
            return Ok(());
        }
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectPostcheckStarted,
            )
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        if let Some(CheckpointRowFetchMaterializationBusyProbeTestBehavior::DelayBeforePostcheck(
            delay,
        )) = test_behavior
        {
            thread::sleep(delay);
        }
        let postcheck_row_count = conn
            .query_row(CHECKPOINT_HEADLINE_ROW_META_ROW_COUNT_SQL, [], |row| {
                row.get::<_, i64>(0)
            })
            .context("failed postcheck row count after zero-timeout materialization busy probe")?
            .max(0) as u64;
        if tx
            .send(
                CheckpointRowFetchMaterializationBusyProbeWorkerMessage::InsertSelectPostcheckCompleted {
                    row_count: postcheck_row_count,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(Ok(())));
        Ok(())
    };

    if let Err(error) = run() {
        let _ = tx.send(
            CheckpointRowFetchMaterializationBusyProbeWorkerMessage::Finished(Err(format!(
                "{error:#}"
            ))),
        );
    }
    Ok(())
}

